mapper.select:
select c.*,
       m.name as member_name,
       m.phone as member_phone,
       d.dept_name
from member_card c
left join member m on c.member_id = m.id
left join sys_dept d on c.dept_id = d.dept_id

    c.is_del = 0
    and c.member_id = #{memberId}
    and m.name like concat('%', #{memberName}, '%')
    and m.phone like concat('%', #{memberPhone}, '%')
    and c.member_no like concat('%', #{memberNo}, '%')
    and c.card_type_id = #{cardTypeId}
    and c.status = #{status}
    and c.sale_order_no like concat('%', #{saleOrderNo}, '%')
    and c.refund_order_no like concat('%', #{refundOrderNo}, '%')
    and c.dept_id = #{deptId}
    and c.create_staff_name like concat('%', #{createStaffName}, '%')

        and c.paid_at >= #{beginPaidAt}


        and c.paid_at <= #{endPaidAt}


        and c.effective_at >= #{beginEffectiveAt}


        and c.effective_at <= #{endEffectiveAt}


        and c.expired_at >= #{beginExpiredAt}


        and c.expired_at <= #{endExpiredAt}

    ${params.dataScope}

order by field(c.status, 1, 0, 3, 2),
         coalesce(c.paid_at, c.effective_at, c.created_at) desc,
         c.id desc

select c.id, c.member_no as memberNo, m.name as memberName, m.phone as memberPhone, c.card_type_id as cardTypeId, c.card_type_name as cardTypeName, c.valid_days as validDays, case c.status when 0 then '待生效' when 1 then '生效中' when 2 then '已过期' when 3 then '已退款' else '未知' end as statusName, case when c.status = 1 then '是' else '否' end as activeFlag, c.sale_order_no as saleOrderNo, c.sale_amount as saleAmount, c.paid_at as paidAt, c.effective_at as effectiveAt, c.expired_at as expiredAt, c.refund_order_no as refundOrderNo, c.refunded_at as refundedAt, c.dept_id as deptId, d.dept_name as deptName, c.create_staff_id as createStaffId, c.create_staff_name as createStaffName, c.remark, c.created_at as createdAt, c.updated_at as updatedAt from member_card c left join member m on c.member_id = m.id left join sys_dept d on c.dept_id = d.dept_id
c.is_del = 0 and c.member_id = #{memberId} and m.name like concat('%', #{memberName}, '%') and m.phone like concat('%', #{memberPhone}, '%') and c.member_no like concat('%', #{memberNo}, '%') and c.card_type_id = #{cardTypeId} and c.status = #{status} and c.sale_order_no like concat('%', #{saleOrderNo}, '%') and c.refund_order_no like concat('%', #{refundOrderNo}, '%') and c.dept_id = #{deptId} and c.create_staff_name like concat('%', #{createStaffName}, '%')
and c.paid_at >= #{beginPaidAt}
and c.paid_at <= #{endPaidAt}
and c.effective_at >= #{beginEffectiveAt}
and c.effective_at <= #{endEffectiveAt}
and c.expired_at >= #{beginExpiredAt}
and c.expired_at <= #{endExpiredAt}
${params.dataScope}
order by field(c.status, 1, 0, 3, 2), coalesce(c.paid_at, c.effective_at, c.created_at) desc, c.id desc
